# RefCOCO (unc), single-dataset fine-tuning + HiLoRA, using the PLAIN OpenAI
# CLIP checkpoint instead of the MSCOCO-debiased one — same procedure as
# train_unc_hilora_real.sh, with --clip_model simply omitted. models/HiVG.py
# always builds self.clip = CLIPModel.from_pretrained("openai/clip-vit-base-patch16")
# first; --clip_model only optionally overlays the debiased weights on top of
# that. Omitting it leaves the vanilla pretrained CLIP in place — this is the
# README's documented "original CLIP Hugging Face model... performance may be
# degraded" alternative path, now used deliberately as an ablation.
#
# Everything else (lr/epochs/batch_size/hi_lora_stage schedule, loss flags) is
# identical to train_unc_hilora_real.sh. Output goes to a separate
# output_v1{0,1,2,3}0_oaiclip tree so it doesn't clobber the debiased-checkpoint run.

DATA_ROOT=$SCRATCH/grounding_data
SPLIT_ROOT=$SCRATCH/grounding_data/data
OUT_ROOT=$SCRATCH/clip-kd-snn/HiVG_outputs

echo -e "\n\n\n\n\n\n\n==================== unc warmup (OAI CLIP) ==========================="
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28887 --use_env hivg_train.py --num_workers 4 --epochs  60 --batch_size 80 --lr 0.00025  --lr_scheduler cosine --aug_crop --aug_scale --aug_translate   --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --dataset unc      --use_contrastive_loss  --use_rtcc_constrain_loss --use_mask_loss  --data_root $DATA_ROOT --split_root $SPLIT_ROOT  --output_dir $OUT_ROOT/output_v100_oaiclip/unc --sup_type full;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss --save_hilora_clip --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v100_oaiclip/unc/best_checkpoint.pth --eval_set val      --output_dir $OUT_ROOT/output_v100_oaiclip/unc;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss --save_hilora_clip --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v100_oaiclip/unc/best_checkpoint.pth --eval_set testA    --output_dir $OUT_ROOT/output_v100_oaiclip/unc;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss --save_hilora_clip --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v100_oaiclip/unc/best_checkpoint.pth --eval_set testB    --output_dir $OUT_ROOT/output_v100_oaiclip/unc;
##
