echo -e "\n\n\n\n\n\n\n==================== unc stage 1 (OAI CLIP) ==========================="
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28887 --use_env hivg_train.py --num_workers 4 --epochs 20  --batch_size 60 --lr 0.00010   --lr_scheduler cosine --aug_crop --aug_scale --aug_translate  --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --dataset unc      --use_contrastive_loss  --use_rtcc_constrain_loss --use_mask_loss  --save_hilora_clip --hi_lora_stage 1 --data_root $DATA_ROOT  --split_root $SPLIT_ROOT --hi_lora_retrain $OUT_ROOT/output_v100_oaiclip/unc/best_checkpoint.pth      --hi_lora_clip $OUT_ROOT/output_v100_oaiclip/unc/clip_lora_stage_with_bridge.pth       --output_dir $OUT_ROOT/output_v101_oaiclip/unc      --sup_type full;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 60  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss  --save_hilora_clip --hi_lora_stage 1 --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v101_oaiclip/unc/best_checkpoint.pth      --eval_set val    --output_dir $OUT_ROOT/output_v101_oaiclip/unc;
